					mScope[sQualifiedName] = oElement;
					if (oElement.$kind === "Schema") {
						that._addUrlForSchema(sQualifiedName, that.aAnnotationURLs[i]);
						that._doMergeAnnotations(oElement, mScope.$Annotations, true);
