						this.getConstraints(oProperty, oMetaContext.getPath()));
				} else {
					Log.warning("Unsupported type '" + oProperty.$Type + "', using "
						+ oType.getName(), sPath, sODataMetaModel);
				}
			}
			if (!mFormatOptions) {
