			var oError = new Error(sResolvedPath + ": " + sMessage);

			if (bNoEditUrl !== undefined) {
				oModel.reportError(sMessage, sODataMetaModel, oError);
			} // else: do not log to console or message model for APIs
			throw oError;
		}

