		return _Helper.clone(this.mParameters.$$aggregation, function (sKey, vValue) {
			return sKey[0] === "$"
				&& !(bVerbose && ["$DistanceFromRoot", "$DrillState",
					"$NodeProperty"].includes(sKey))
				? undefined
