					}
					// update the cache with the PATCH response
					_Helper.updateExisting(that.mChangeListeners, sEntityPath, oEntity,
						bPatchWithoutSideEffects
							? {"@odata.etag" : oPatchResult["@odata.etag"]}
							: oPatchResult);
