								+ " when updating " + sFullPath, that.toString(), sClassName);
					} else {
						// some servers need unit and currency information
						_Helper.merge(oUnitOrCurrencyTarget,
							_Helper.makeUpdateData(aUnitOrCurrencyPath, sUnitOrCurrencyValue));
