			? new SyncPromise((resolve) => {
				aAdditionalRowHandlers.push((oGrandTotal) => {
					_AggregationHelper.handleGrandTotal(oAggregation, oGrandTotal);
					resolve(oGrandTotal);
				});
			})
			: undefined;

